    ABOUT_ENDPOINT,
    ACCESS_TOKEN_ENDPOINT,
    BULLETIN_BOARD_ENDPOINT,
    CLUSTER_SUMMARY_ENDPOINT,
    FLOW_STATUS_ENDPOINT,
    PROCESS_GROUP_STATUS_ENDPOINT,
    SYSTEM_DIAGNOSTICS_ENDPOINT,
)


class NiFiApi:
    def __init__(self, api_url, http, log, username=None, password=None):
        self._api_url = api_url.rstrip('/')
        self._http = http
        self._log = log
        self._username = username
        self._password = password
        self._token = None

    def _authenticate(self):
        """Obtain a bearer token via POST /access/token (expects HTTP 201)."""
        resp = self._http.post(
            f'{self._api_url}{ACCESS_TOKEN_ENDPOINT}',
            data={'username': self._username, 'password': self._password},
            extra_headers={'Content-Type': 'application/x-www-form-urlencoded'},
        )
        if resp.status_code != 201:
            raise HTTPError(f'Expected 201 from token endpoint, got {resp.status_code}', response=resp)
        self._token = resp.text
        self._log.debug('Obtained NiFi auth token (%d chars)', len(self._token))

    def _ensure_auth(self):
        """Authenticate if we don't have a token yet."""
        if not self._token and self._username and self._password:
            self._authenticate()

    def _request(self, path):
        """GET a JSON endpoint, authenticating and retrying once on 401."""
        self._ensure_auth()
        url = f'{self._api_url}{path}'
        extra = {}
        if self._token:
            extra['Authorization'] = f'Bearer {self._token}'

        resp = self._http.get(url, extra_headers=extra)

        if resp.status_code == 401 and self._username and self._password:
            self._log.debug('Got 401, re-authenticating')
            self._authenticate()
            extra['Authorization'] = f'Bearer {self._token}'
            resp = self._http.get(url, extra_headers=extra)

        resp.raise_for_status()
        return resp.json()

    def get_about(self):
        """GET /flow/about — returns the NiFi version string."""
        data = self._request(ABOUT_ENDPOINT)
        return data.get('about', {}).get('version', 'unknown')

    def get_cluster_summary(self):
        """GET /flow/cluster/summary — returns cluster health info."""
        return self._request(CLUSTER_SUMMARY_ENDPOINT)

    def get_system_diagnostics(self):
        """GET /system-diagnostics — returns JVM, GC, and repository metrics."""
        return self._request(SYSTEM_DIAGNOSTICS_ENDPOINT)

    def get_flow_status(self):
        """GET /flow/status — returns controller-level flow summary."""
        return self._request(FLOW_STATUS_ENDPOINT)

    def get_process_group_status(self, pg_id, recursive=True):
        """GET /flow/process-groups/{id}/status — returns process group metrics."""
        path = PROCESS_GROUP_STATUS_ENDPOINT.format(pg_id)
        if recursive:
            path += '?recursive=true'
        return self._request(path)

    def get_bulletin_board(self):
        """GET /flow/bulletin-board — returns recent bulletins."""
        return self._request(BULLETIN_BOARD_ENDPOINT)

